css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #050d0a; color: white; }
.layout { display: flex; min-height: 100vh; }
aside { width: 240px; background: #0a1a12; border-right: 1px solid rgba(34,197,94,0.1); display: flex; flex-direction: column; padding: 24px 14px; flex-shrink: 0; }
.brand { font-size: 20px; font-weight: 800; padding: 0 10px; margin-bottom: 28px; }
nav { flex: 1; display: flex; flex-direction: column; gap: 4px; }
.nav-item { display: block; padding: 12px 14px; border-radius: 10px; color: #6b7280; font-size: 14px; font-weight: 500; cursor: pointer; transition: all 0.2s; } .nav-item:hover { background: rgba(34,197,94,0.08); color: white; } .nav-item.active { background: rgba(34,197,94,0.15); color: #22c55e; font-weight: 600; }
.sidebar-footer { border-top: 1px solid rgba(255,255,255,0.07); padding-top: 16px; margin-top: 16px; }
.user-info { display: flex; align-items: center; gap: 10px; } .user-av { width: 36px; height: 36px; border-radius: 50%; background: linear-gradient(135deg, #22c55e, #16a34a); display: flex; align-items: center; justify-content: center; font-size: 12px; font-weight: 800; }
.user-info strong { display: block; font-size: 13px; } .user-info small { color: #22c55e; font-size: 11px; }
main { flex: 1; padding: 24px; overflow-y: auto; }
.topbar { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; }
.topbar h1 { font-size: 24px; font-weight: 800; } .topbar p { color: #6b7280; font-size: 13px; margin-top: 2px; }
.tb-actions { display: flex; gap: 10px; }
.tb-btn { padding: 10px 18px; border-radius: 10px; border: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.05); color: white; font-size: 13px; font-weight: 600; cursor: pointer; } .tb-btn.export { border-color: rgba(34,197,94,0.3); color: #22c55e; }
.balance-row { display: grid; grid-template-columns: 1.5fr 1fr 1fr 1fr; gap: 14px; margin-bottom: 20px; }
.balance-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); border-radius: 14px; padding: 18px; }
.balance-card.main { background: linear-gradient(135deg, rgba(34,197,94,0.15), rgba(16,163,74,0.08)); border-color: rgba(34,197,94,0.2); }
.bc-label { display: block; font-size: 12px; color: #6b7280; margin-bottom: 8px; }
.bc-amount { display: block; font-size: 22px; font-weight: 800; margin-bottom: 6px; }
.bc-change { font-size: 12px; font-weight: 600; } .up { color: #22c55e; } .down { color: #ef4444; }
.content-row { display: grid; grid-template-columns: 1.5fr 1fr; gap: 16px; margin-bottom: 16px; }
.chart-card, .budget-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); border-radius: 14px; padding: 20px; }
.cc-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 16px; } .cc-header h3 { font-size: 15px; font-weight: 700; }
.legend { display: flex; gap: 14px; font-size: 12px; }
.leg { display: flex; align-items: center; gap: 6px; color: #9ca3af; } .leg::before { content: ''; width: 10px; height: 10px; border-radius: 50%; display: inline-block; } .leg.green::before { background: #22c55e; } .leg.red::before { background: #ef4444; }
.bar-chart { display: flex; align-items: flex-end; gap: 10px; height: 140px; }
.bc-group { flex: 1; display: flex; align-items: flex-end; gap: 3px; flex-direction: column; } .bc-label-x { font-size: 10px; color: #4b5563; text-align: center; margin-top: 6px; }
.bc-wrap { flex: 1; display: flex; align-items: flex-end; gap: 3px; width: 100%; }
.bc-bar { flex: 1; border-radius: 4px; }
.budget-card h3 { font-size: 15px; font-weight: 700; margin-bottom: 16px; }
.budget-list { display: flex; flex-direction: column; gap: 14px; }
.bi-top { display: flex; justify-content: space-between; font-size: 13px; margin-bottom: 6px; } .bi-top span:last-child { color: #9ca3af; font-size: 12px; }
.bi-bar { height: 6px; background: rgba(255,255,255,0.08); border-radius: 3px; } .bi-fill { height: 100%; border-radius: 3px; transition: width 0.5s ease; }
.transactions-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); border-radius: 14px; padding: 20px; }
.tc-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 16px; } .tc-header h3 { font-size: 15px; font-weight: 700; }
.see-all { background: none; border: none; color: #22c55e; font-size: 13px; font-weight: 600; cursor: pointer; }
.tx-list { display: flex; flex-direction: column; }
.tx-item { display: flex; align-items: center; gap: 12px; padding: 12px 0; border-bottom: 1px solid rgba(255,255,255,0.05); }
.tx-icon { width: 36px; height: 36px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 14px; font-weight: 800; flex-shrink: 0; } .tx-icon.income { background: rgba(34,197,94,0.15); color: #22c55e; } .tx-icon.expense { background: rgba(239,68,68,0.15); color: #ef4444; }
.tx-info { flex: 1; } .tx-info strong { display: block; font-size: 14px; } .tx-info small { color: #6b7280; font-size: 12px; }
.tx-amount { font-size: 15px; font-weight: 700; } .tx-amount.income { color: #22c55e; } .tx-amount.expense { color: #ef4444; }

