const months = ['Eki','Kas','Ara','Oca'];
const incomes = [28000,30000,27000,32500];
const expenses = [16000,19000,17500,18240];
const chart = document.getElementById('bar-chart');
const max = Math.max(...incomes,...expenses);
chart.innerHTML = months.map((m,i) => `
  <div style='flex:1;display:flex;flex-direction:column;align-items:center;gap:4px;height:100%'>
    <div style='flex:1;display:flex;align-items:flex-end;gap:3px;width:100%'>
      <div style='flex:1;border-radius:4px;background:#22c55e;height:${(incomes[i]/max*100)}%'></div>
      <div style='flex:1;border-radius:4px;background:#ef4444;height:${(expenses[i]/max*100)}%'></div>
    </div>
    <span style='font-size:10px;color:#4b5563'>${m}</span>
  </div>
`).join('');
document.querySelectorAll('.nav-item').forEach(item => { item.addEventListener('click', function() { document.querySelectorAll('.nav-item').forEach(i => i.classList.remove('active')); this.classList.add('active'); }); });
